&lt;ul&gt;
&lt;li&gt;&lt;span class=&quot;NormalTextRun SCXW42763644 BCX0&quot;&gt;Bachelor’s degree&lt;/span&gt;&lt;span class=&quot;NormalTextRun SCXW42763644 BCX0&quot;&gt; o&lt;/span&gt;&lt;span class=&quot;NormalTextRun SCXW42763644 BCX0&quot;&gt;r related field&lt;/span&gt;&lt;span class=&quot;NormalTextRun SCXW42763644 BCX0&quot;&gt;; &lt;/span&gt;&lt;span class=&quot;NormalTextRun ContextualSpellingAndGrammarErrorV2Themed SCXW42763644 BCX0&quot;&gt;Mas&lt;/span&gt;&lt;span class=&quot;NormalTextRun ContextualSpellingAndGrammarErrorV2Themed SCXW42763644 BCX0&quot;&gt;ter’s in Taxation&lt;/span&gt;&lt;span class=&quot;NormalTextRun SCXW42763644 BCX0&quot;&gt; preferred&lt;/span&gt; &lt;span class=&quot;NormalTextRun SCXW42763644 BCX0&quot;&gt;(CPA or CPA candidate preferred)&lt;/s

